const rows = $input.all().map((item) => {
  const r = item.json || {};
  const emails = (r.all_emails || '').toString().trim();
  const cats = (r.all_categories || '').toString().trim();
  const rating = Number(r.review_rating) || 0;
  const reviews = Number(r.review_count) || 0;
  const hasEmail = emails ? 1 : 0;
  const hasWebsite = r.website ? 1 : 0;
  const score = Math.round(Math.min(100, rating * Math.log10(reviews + 1) * 12 + hasEmail * 15 + hasWebsite * 5));
  return { json: { search_rank: r.search_rank ?? '', title: r.title || '', phone: r.phone || '', website: r.website || '', emails, primary_category: r.primary_category || '', categories: cats, review_rating: r.review_rating ?? '', review_count: r.review_count ?? '', status: r.status || '', city: r.city || '', state: r.state || '', address: r.address || '', place_url: r.url || '', lead_score: score, source_keyword: r.source_keyword || '', source_location: r.source_location || '', scraped_at: r.scraped_at || '' } };
});
return rows.sort((a, b) => b.json.lead_score - a.json.lead_score);

const rows = ($input.first().json.rows || []).slice();
const total = rows.length;
const withEmail = rows.filter(r => r.emails).length;
const emailRate = total ? Math.round(withEmail * 100 / total) : 0;
const top = rows.slice(0, 10);
const esc = (s) => String(s ?? '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const tr = (r) => `<tr><td>${esc(r.lead_score)}</td><td>${esc(r.title)}</td><td>${esc(r.review_rating)}★ (${esc(r.review_count)})</td><td>${esc(r.emails)||'—'}</td><td>${esc(r.phone)||'—'}</td><td>${esc(r.primary_category)}</td></tr>`;
const table = top.length ? `<table border="1" cellpadding="6" cellspacing="0" style="border-collapse:collapse;font-size:13px;"><thead><tr><th>Score</th><th>Title</th><th>Rating</th><th>Email</th><th>Phone</th><th>Category</th></tr></thead><tbody>${top.map(tr).join('')}</tbody></table>` : '<p>No records.</p>';
const html = `<h2>CoreClaw Maps Leads — Callback Summary</h2><p>Total leads: <b>${total}</b> · With email: <b>${withEmail}</b> (${emailRate}%)</p>${table}<p style="color:#888;font-size:12px;">Full data attached as gmaps-leads.xlsx.</p>`;
return [{ json: { html, total, withEmail, emailRate } }];

// Rename the downloaded xlsx binary to a stable filename for the email attachment
for (const item of $input.all()) {
  if (item.binary?.data) {
    item.binary.data.fileName = "gmaps-leads.xlsx";
  }
}
return $input.all();
